import{_ as a,H as e,f as i,i as s}from"./chunks/framework.DLd0CbzH.js";const u=JSON.parse('{"title":"二维码生成","description":"","frontmatter":{},"headers":[],"relativePath":"api/qrcode-generator.md","filePath":"api/qrcode-generator.md","lastUpdated":1780717908000}'),d={name:"api/qrcode-generator.md"};function o(l,t,n,h,p,r){return e(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="二维码生成" tabindex="-1">二维码生成 <a class="header-anchor" href="#二维码生成" aria-label="Permalink to &quot;二维码生成&quot;">​</a></h1><p>生成 QR Code 二维码，支持 PNG、SVG、PDF 三种输出格式，可自定义纠错等级、边距、尺寸等参数。</p><h2 id="接口信息" tabindex="-1">接口信息 <a class="header-anchor" href="#接口信息" aria-label="Permalink to &quot;接口信息&quot;">​</a></h2><ul><li><strong>请求方法</strong>：<code>GET</code></li><li><strong>请求路径</strong>：<code>/qrcode</code></li></ul><h2 id="请求参数" tabindex="-1">请求参数 <a class="header-anchor" href="#请求参数" aria-label="Permalink to &quot;请求参数&quot;">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>类型</th><th>必填</th><th>默认值</th><th>描述</th></tr></thead><tbody><tr><td>text</td><td>string</td><td><strong>是</strong></td><td>无</td><td>需要编码为二维码的内容（URL、文本、数字等）</td></tr><tr><td>type</td><td>string</td><td>否</td><td><code>png</code></td><td>输出格式：<code>png</code>（栅格图，默认）、<code>svg</code>（矢量图）、<code>pdf</code>（文档）</td></tr><tr><td>level</td><td>string</td><td>否</td><td><code>M</code></td><td>纠错等级：<code>L</code>(7%)、<code>M</code>(15%)、<code>Q</code>(25%)、<code>H</code>(30%)</td></tr><tr><td>margin</td><td>integer</td><td>否</td><td><code>2</code></td><td>二维码四周留白（模块数），范围 0–10</td></tr><tr><td>size</td><td>integer</td><td>否</td><td><code>200</code></td><td><strong>仅 PNG 有效</strong>。二维码图片边长（像素），范围 50–1000，步长 10</td></tr><tr><td>parse_url</td><td>boolean</td><td>否</td><td><code>false</code></td><td>是否对 URL 进行实验性优化（可改善长链接的编码效率）</td></tr></tbody></table><h2 id="响应说明" tabindex="-1">响应说明 <a class="header-anchor" href="#响应说明" aria-label="Permalink to &quot;响应说明&quot;">​</a></h2><ul><li><strong>成功时</strong>：根据 <code>type</code> 参数返回对应的二进制数据。 <ul><li><code>type=png</code> → <code>Content-Type: image/png</code></li><li><code>type=svg</code> → <code>Content-Type: image/svg+xml</code></li><li><code>type=pdf</code> → <code>Content-Type: application/pdf</code></li></ul></li><li><strong>失败时</strong>：返回 JSON 格式的错误信息。 <ul><li>缺少 <code>text</code> 参数时返回 HTML 表单页面（可直接交互）。</li><li>无效的 <code>type</code> 参数返回 <code>{&quot;code&quot;:400,&quot;message&quot;:&quot;Invalid type parameter&quot;}</code>。</li></ul></li></ul><h2 id="说明" tabindex="-1">说明 <a class="header-anchor" href="#说明" aria-label="Permalink to &quot;说明&quot;">​</a></h2><ul><li>该接口无需认证，可直接调用。</li><li>响应头中设置了 <code>Cache-Control: public, max-age=3600</code>，同一参数生成的二维码会缓存 1 小时。</li><li>直接访问 <code>/qrcode</code> 不带任何参数时，会返回一个美观的 HTML 生成表单，用户可填写内容并即时生成二维码。</li></ul><h2 id="调用示例" tabindex="-1">调用示例 <a class="header-anchor" href="#调用示例" aria-label="Permalink to &quot;调用示例&quot;">​</a></h2><h3 id="_1-生成-png-二维码-默认尺寸-200px" tabindex="-1">1. 生成 PNG 二维码（默认尺寸 200px） <a class="header-anchor" href="#_1-生成-png-二维码-默认尺寸-200px" aria-label="Permalink to &quot;1. 生成 PNG 二维码（默认尺寸 200px）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://api.undz.cn/qrcode?text=https://example.com&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qrcode.png</span></span></code></pre></div><h3 id="_2-生成-svg-矢量图-h-级纠错-边距-4-模块" tabindex="-1">2. 生成 SVG 矢量图，H 级纠错，边距 4 模块 <a class="header-anchor" href="#_2-生成-svg-矢量图-h-级纠错-边距-4-模块" aria-label="Permalink to &quot;2. 生成 SVG 矢量图，H 级纠错，边距 4 模块&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://api.undz.cn/qrcode?text=Hello%20World&amp;type=svg&amp;level=H&amp;margin=4&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qrcode.svg</span></span></code></pre></div><h3 id="_3-生成-pdf-文档-二维码占据整页" tabindex="-1">3. 生成 PDF 文档（二维码占据整页） <a class="header-anchor" href="#_3-生成-pdf-文档-二维码占据整页" aria-label="Permalink to &quot;3. 生成 PDF 文档（二维码占据整页）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://api.undz.cn/qrcode?text=你好&amp;type=pdf&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qrcode.pdf</span></span></code></pre></div><h3 id="_4-生成大尺寸-png-500px-url-优化" tabindex="-1">4. 生成大尺寸 PNG（500px，URL 优化） <a class="header-anchor" href="#_4-生成大尺寸-png-500px-url-优化" aria-label="Permalink to &quot;4. 生成大尺寸 PNG（500px，URL 优化）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://api.undz.cn/qrcode?text=https://example.com/very/long/path&amp;size=500&amp;parse_url=true&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qrcode.png</span></span></code></pre></div><h3 id="_5-在-html-中直接引用" tabindex="-1">5. 在 HTML 中直接引用 <a class="header-anchor" href="#_5-在-html-中直接引用" aria-label="Permalink to &quot;5. 在 HTML 中直接引用&quot;">​</a></h3><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">img</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://api.undz.cn/qrcode?text=你好&amp;size=300&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> alt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;QR Code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h2 id="前端表单页面预览" tabindex="-1">前端表单页面预览 <a class="header-anchor" href="#前端表单页面预览" aria-label="Permalink to &quot;前端表单页面预览&quot;">​</a></h2><p>访问 <code>/qrcode</code> 即可看到如下交互界面（自动适配移动端）：</p><p><img src="https://net.undz.cn/static/png/3714d87625b0481cffad90ea09fe52ac.png" alt="表单预览"> <em>（示意，实际请自行体验）</em></p><p>包含格式选择、纠错等级、尺寸、边距等控件，点击“生成二维码”即可实时获取结果。</p>',25)])])}const g=a(d,[["render",o]]);export{u as __pageData,g as default};
